+int _lbuf_rd(struct lbuf *lb, int fd, int beg, int end, int init)
+{
+	if (!init) {
+		struct stat st;
+		long nr;	/* 1048575 caps at 2147481600 on 32 bit */
+		int sz = 1048575, step = 1, n = 0;
+		if (fstat(fd, &st) >= 0 && S_ISREG(st.st_mode))
+			sz = st.st_size >= INT_MAX ? INT_MAX : st.st_size + step;
+		char *s = emalloc(sz--);
+		while ((nr = read(fd, s + n, sz - n)) > 0) {
+			n += nr;
+			if (n >= sz + step) {
+				if (n > INT_MAX / 2) {
+					n -= nr;
+					break;
+				}
+				sz = n * 2;
+				s = erealloc(s, sz--);
+				step = 1;
+			} else if (n == sz) {
+				sz++;
+				step = 0;
+			}
+		}
+		s[n] = '\0';
+		lbuf_edit(lb, s, beg, end, 0, 0);
+		free(s);
+		return nr != 0;
+	}
+	long nr, l, nins = 0, nl = 0;
+	struct linfo *n, *cn = NULL;
+	const int rchunk = 4096;
+	char sm[rchunk+1], *s, *ln;
+	sbuf_smake(sb, 0)
+	while ((nr = read(fd, sm, rchunk)) > 0) {
+		s = sm;
+		s[nr] = '\0';
+		for (; *s; nins++) {
+			l = linelength(s);
+			nl = (s[l - !!l] == '\n');
+			int l_nonl = l - nl;
+			if (!cn) {
+				n = emalloc(l_nonl + 5 + sizeof(struct linfo));
+				n->len = l_nonl;
+				n->grec = 0;
+				ln = (char*)(n + 1);
+				memcpy(ln, s, l_nonl);
+				memset(&ln[l_nonl + 1], 0, 4);	/* fault tolerance pad */
+				ln[l_nonl] = '\n';
+			} else {
+				n = erealloc(cn, cn->len + l_nonl + 5 + sizeof(struct linfo));
+				ln = (char*)(n + 1);
+				memcpy(ln + n->len, s, l_nonl);
+				n->len += l_nonl;
+				cn = NULL;
+				memset(&ln[n->len + 1], 0, 4);	/* fault tolerance pad */
+				ln[n->len] = '\n';
 			}
-			sz = n * 2;
-			s = erealloc(s, sz--);
-			step = 1;
-		} else if (n == sz) {
-			sz++;
-			step = 0;
+			sbuf_mem(sb, &ln, (int)sizeof(ln))
+			s += l;
+		}
+		if (s - sm != rchunk) {
+			nr = 0;
+			break;
+		}
+		if (!nl) {
+			cn = n;
+			nins--;
+			sb->s_n -= sizeof(ln);
 		}
 	}
-	s[n] = '\0';
-	lbuf_edit(lb, s, beg, end, 0, 0);
-	free(s);
+	sbuf_null(sb)
+	lbuf_edit(lb, sb->s, beg, end, 0, 0);
+	lb->ln_n = nins;
+	lb->ln = emalloc((nins + 512) * sizeof(lb->ln[0]));
+	lb->ln_sz = nins + 512;
+	for (int i = 0; i < nins; i++)
+		lb->ln[i] = *((char**)sb->s + i);
+	free(sb->s);
 	return nr != 0;
 }
 
+static long write_fully(int fd, char *buf, long sz)
+{
+	long nw = 0, nc = 0;
+	while (nw < sz && (nc = write(fd, buf + nw, sz - nw)) >= 0)
+		nw += nc;
+	return nc >= 0 ? nw : -1;
+}
+
 int lbuf_wr(struct lbuf *lb, int fd, int beg, int end)
 {
+	char buf[4096];
+	long buf_len = 0;
 	for (int i = beg; i < end; i++) {
 		char *ln = lb->ln[i];
-		long nw = 0;
 		long nl = lbuf_s(ln)->len + 1;
-		while (nw < nl) {
-			long nc = write(fd, ln + nw, nl - nw);
-			if (nc < 0)
-				return nc;
-			nw += nc;
+		if (buf_len > 0 && buf_len + nl > (long)sizeof(buf)) {
+			if (write_fully(fd, buf, buf_len) < 0)
+				return -1;
+			buf_len = 0;
+		}
+		if (nl >= (long)sizeof(buf)) {
+			if (write_fully(fd, ln, nl) < 0)
+				return -1;
+		} else {
+			memcpy(buf + buf_len, ln, nl);
+			buf_len += nl;
 		}
 	}
+	if (buf_len > 0 && write_fully(fd, buf, buf_len) < 0)
+		return -1;
 	return 0;
 }
 
